//Copyright(c)HashiCorp,Inc.//SPDX-License-Identifier:MPL-2.0packagedocdbimport("strings""testing")funcTestValidIdentifier(t*testing.T){t.Parallel()validNames:=[]string{"a","hello-world","hello-world-0123456789",strings.Repeat("w",63),}for_,v:=rangevalidNames{_,errors:=validIdentifier(v,"name")iflen(errors)!=0{t.Fatalf("%qshouldbeavalidDocumentDBIdentifier:%q",v,errors)}}invalidNames:=[]string{"","special@character","slash/in-the-middle","dot.in-the-middle","two-hyphen--in-the-middle","0-first-numeric","-first-hyphen","end-hyphen-",strings.Repeat("W",64),}for_,v:=rangeinvalidNames{_,errors:=validIdentifier(v,"name")iflen(errors)==0{t.Fatalf("%qshouldbeaninvalidDocumentDBIdentifier",v)}}}